import android.annotation.SuppressLint
import android.app.Activity
import android.content.SharedPreferences
import android.os.Bundle
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class LoginActivity : Activity() {
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var sharedPreferences: SharedPreferences

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        // Initialize shared preferences
        sharedPreferences = getSharedPreferences("authenticated", ContextCompat.getMainExecutor())

        // Initialize biometric prompt
        val executor: Executor = ContextCompat.getMainExecutor()
        biometricPrompt = BiometricPrompt(this, executor) { isAuthenticated ->
            if (isAuthenticated) {
                // Store authenticated flag in shared preferences
                val editor = sharedPreferences.edit()
                editor.putBoolean("authenticated", true).apply()

                // Bypass login screen and go to home screen
                startActivity(Intent(this, HomeScreen::class.java))
            } else {
                // Fallback to password authentication
                val intent = Intent(this, PasswordLoginActivity::class.java)
                startActivity(intent)
            }
        }
    }

    fun showBiometricPrompt() {
        biometricPrompt.authenticate(null, BiometricPrompt.AUTH_FAILED_REASON_LOCKOUT)
    }
}